-- Feature 5: Genera Documenti
-- Tables for document templates and generated documents

CREATE TABLE IF NOT EXISTS documenti_sistema (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  club_id       UUID REFERENCES clubs(id) ON DELETE CASCADE,  -- NULL = template di sistema
  categoria     TEXT NOT NULL,   -- dichiarazioni | contratti | privacy | tesseramento | varie
  titolo        TEXT NOT NULL,
  descrizione   TEXT,
  corpo_html    TEXT NOT NULL,   -- HTML con {{placeholder}}
  placeholders  JSONB DEFAULT '[]'::jsonb,  -- array di {chiave, etichetta, tipo}
  is_sistema    BOOLEAN DEFAULT true,
  attivo        BOOLEAN DEFAULT true,
  ordine        INT DEFAULT 0,
  created_at    TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS documenti_generati (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  club_id         UUID REFERENCES clubs(id) ON DELETE CASCADE,
  documento_id    UUID REFERENCES documenti_sistema(id),
  giocatore_id    UUID REFERENCES giocatori(id),
  titolo          TEXT NOT NULL,
  corpo_html      TEXT NOT NULL,
  generato_da     UUID REFERENCES utenti(id),
  generato_il     TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE documenti_sistema DISABLE ROW LEVEL SECURITY;
ALTER TABLE documenti_generati DISABLE ROW LEVEL SECURITY;

CREATE INDEX IF NOT EXISTS documenti_sistema_categoria ON documenti_sistema(categoria);
CREATE INDEX IF NOT EXISTS documenti_generati_club ON documenti_generati(club_id);
CREATE INDEX IF NOT EXISTS documenti_generati_giocatore ON documenti_generati(giocatore_id);

-- Seed: 24 documenti di sistema (club_id = NULL → disponibili per tutti i club)
