(NULL, 'contratti', 'Contratto Collaborazione Coordinata (Co.Co.Co.) – Allenatore',
 'Contratto di collaborazione coordinata e continuativa per allenatore D.Lgs. 36/2021',
 '<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;font-size:11pt;margin:40px;line-height:1.7}h1{font-size:14pt;text-align:center}h2{font-size:12pt;margin-top:20px}p{margin:6px 0}.firma{margin-top:50px;display:flex;justify-content:space-between;gap:40px}</style></head><body><h1>CONTRATTO DI COLLABORAZIONE COORDINATA E CONTINUATIVA</h1><h1>D.LGS. 28 FEBBRAIO 2021, N. 36</h1><p style="text-align:center;margin-top:4px"><strong>Settore Dilettantistico – Figura Tecnica: ALLENATORE</strong></p><h2>Tra le parti:</h2><p><strong>{{club_nome}}</strong> (di seguito "Società"), C.F. {{club_cf}}, con sede in {{club_indirizzo}}, rappresentata dal Presidente <strong>{{legale_nome}}</strong>,</p><p>e il Sig./Sig.ra <strong>{{collaboratore_nome}}</strong> (di seguito "Collaboratore"), nato/a a {{collaboratore_nato_a}} il {{collaboratore_data_nascita}}, C.F. {{collaboratore_cf}}, residente in {{collaboratore_indirizzo}};</p><h2>si conviene quanto segue:</h2><p><strong>Art. 1 – Oggetto.</strong> La Società affida al Collaboratore l''incarico di Allenatore della squadra {{nome_squadra}} (categoria {{categoria}}) per la stagione sportiva {{stagione}}.</p><p><strong>Art. 2 – Durata.</strong> Il presente contratto ha durata dal {{data_inizio}} al {{data_fine}}.</p><p><strong>Art. 3 – Compenso.</strong> La Società corrisponderà al Collaboratore un compenso lordo complessivo di € {{compenso_lordo}}, da erogarsi con le seguenti modalità: {{modalita_pagamento}}.</p><p><strong>Art. 4 – Trattamento fiscale.</strong> Il compenso è assoggettato al regime fiscale previsto dal D.Lgs. 36/2021 e successive modificazioni. La soglia di esenzione annua è pari a € 5.000,00.</p><p><strong>Art. 5 – Obblighi del Collaboratore.</strong> Il Collaboratore si impegna a svolgere l''attività con diligenza professionale, a rispettare il Regolamento interno della Società e le norme federali.</p><p><strong>Art. 6 – Riservatezza.</strong> Il Collaboratore si impegna a mantenere la riservatezza sulle informazioni relative alla Società e agli atleti.</p><p><strong>Art. 7 – Risoluzione.</strong> Il contratto può essere risolto con preavviso di {{preavviso}} giorni da entrambe le parti.</p><div class="firma"><div><p>Per la Società</p><br><p>________________________</p><p><strong>{{legale_nome}}</strong></p><p>Presidente</p></div><div><p>Il Collaboratore</p><br><p>________________________</p><p><strong>{{collaboratore_nome}}</strong></p></div></div><p style="margin-top:20px">Luogo e data: <strong>{{citta}}, {{data}}</strong></p></body></html>',
 '[{"chiave":"stagione","etichetta":"Stagione sportiva","tipo":"text"},{"chiave":"nome_squadra","etichetta":"Nome squadra","tipo":"text"},{"chiave":"categoria","etichetta":"Categoria","tipo":"text"},{"chiave":"collaboratore_nome","etichetta":"Nome collaboratore","tipo":"text"},{"chiave":"collaboratore_cf","etichetta":"CF collaboratore","tipo":"text"},{"chiave":"collaboratore_nato_a","etichetta":"Nato a","tipo":"text"},{"chiave":"collaboratore_data_nascita","etichetta":"Data nascita","tipo":"text"},{"chiave":"collaboratore_indirizzo","etichetta":"Indirizzo collaboratore","tipo":"text"},{"chiave":"compenso_lordo","etichetta":"Compenso lordo €","tipo":"text"},{"chiave":"modalita_pagamento","etichetta":"Modalità pagamento","tipo":"text"},{"chiave":"data_inizio","etichetta":"Data inizio","tipo":"text"},{"chiave":"data_fine","etichetta":"Data fine","tipo":"text"},{"chiave":"preavviso","etichetta":"Preavviso (giorni)","tipo":"text"},{"chiave":"data","etichetta":"Data firma","tipo":"text"}]'::jsonb,
